module verified_up_down_counter(
    input reset_clk,
    input rst,
    input up,
    input down,
    output reg [2:0] count
);
    always @(posedge reset_clk or posedge rst) begin
        if (rst)
            count <= 3'b000;
        else if (up && !down)
            count <= count + 1;
        else if (!up && down)
            count <= count - 1;
    end
endmodule
